try (MyResource r = new MyResource()) {
    throw new RuntimeException("Main logic failed");
} catch (Exception e) {
    // e is "Main logic failed"
    // e.getSuppressed()[0] contains the exception thrown by r.close()
}

class Parent {
    void doWork() throws IOException {}
}
class Child extends Parent {
    // VALID: FileNotFoundException is a subclass of IOException
    // VALID: Throwing no checked exceptions is fine
    // INVALID: void doWork() throws Exception {} (Exception is broader)
    @Override
    void doWork() throws FileNotFoundException, NullPointerException {}
}

